"use strict";(self.webpackChunkshareme=self.webpackChunkshareme||[]).push([["3782"],{14317(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"data-conversion-tool-guide","metadata":{"permalink":"/shareme/blog/data-conversion-tool-guide","source":"@site/blog/2026/index.mdx","title":"H\u01B0\u1EDBng D\u1EABn S\u1EED D\u1EE5ng Tool Data Converter","description":"Trong l\u0129nh v\u1EF1c t\u1EF1 \u0111\u1ED9ng h\xf3a, l\u1EADp tr\xecnh PLC/SCADA/HMI v\xe0 thi\u1EBFt k\u1EBF thi\u1EBFt b\u1ECB IoT c\xf4ng nghi\u1EC7p, vi\u1EC7c x\u1EED l\xfd d\u1EEF li\u1EC7u th\xf4 (raw bytes) t\u1EEB c\xe1c c\u1EA3m bi\u1EBFn hay c\u01A1 c\u1EA5u ch\u1EA5p h\xe0nh qua \u0111\u01B0\u1EDDng truy\u1EC1n RS-485 / Modbus RTU l\xe0 c\xf4ng vi\u1EC7c th\u01B0\u1EDDng xuy\xean di\u1EC5n ra h\xe0ng ng\xe0y...","date":"2026-07-19T13:19:20.000Z","tags":[{"inline":false,"label":"Data Conversion","permalink":"/shareme/blog/tags/data-conversion"},{"inline":false,"label":"IEEE 754","permalink":"/shareme/blog/tags/ieee754"},{"inline":false,"label":"CRC16","permalink":"/shareme/blog/tags/crc16"},{"inline":false,"label":"Modbus","permalink":"/shareme/blog/tags/modbus"}],"readingTime":14.03,"hasTruncateMarker":true,"authors":[{"name":"An Nguy\u1EC5n","title":"Th\u1EE3 \u0111\u1EE5ng, t\u1EADp \u0111\u1EE5ng","url":"https://2naq.github.io/shareme","page":{"permalink":"/shareme/blog/authors/an-nguyen"},"socials":{"zalo":"https://zalo.me/2naq","github":"https://github.com/2Naq","newsletter":"https://2naq.github.io/shareme"},"imageURL":"https://github.com/2Naq.png","key":"anTng"},{"name":"S\xe9bastien Lorber","title":"Docusaurus maintainer","url":"https://sebastienlorber.com","page":{"permalink":"/shareme/blog/authors/all-sebastien-lorber-articles"},"socials":{"x":"https://x.com/sebastienlorber","linkedin":"https://www.linkedin.com/in/sebastienlorber/","github":"https://github.com/slorber","newsletter":"https://thisweekinreact.com"},"imageURL":"https://github.com/slorber.png","key":"slorber"},{"name":"Yangshun Tay","title":"Ex-Meta Staff Engineer, Co-founder GreatFrontEnd","url":"https://linkedin.com/in/yangshun","page":{"permalink":"/shareme/blog/authors/yangshun"},"socials":{"x":"https://x.com/yangshunz","linkedin":"https://www.linkedin.com/in/yangshun/","github":"https://github.com/yangshun","newsletter":"https://www.greatfrontend.com"},"imageURL":"https://github.com/yangshun.png","key":"yangshun"}],"frontMatter":{"slug":"data-conversion-tool-guide","title":"H\u01B0\u1EDBng D\u1EABn S\u1EED D\u1EE5ng Tool Data Converter","authors":["anTng","slorber","yangshun"],"tags":["data-conversion","ieee754","crc16","modbus"],"image":"https://pbs.twimg.com/media/HNSX94cawAAw37i.png"},"unlisted":false},"content":"import MathRenderer from \\"@site/src/components/MathRenderer\\";\\n\\nTrong l\u0129nh v\u1EF1c t\u1EF1 \u0111\u1ED9ng h\xf3a, l\u1EADp tr\xecnh PLC/SCADA/HMI v\xe0 thi\u1EBFt k\u1EBF thi\u1EBFt b\u1ECB IoT c\xf4ng nghi\u1EC7p, vi\u1EC7c x\u1EED l\xfd d\u1EEF li\u1EC7u th\xf4 (raw bytes) t\u1EEB c\xe1c c\u1EA3m bi\u1EBFn hay c\u01A1 c\u1EA5u ch\u1EA5p h\xe0nh qua \u0111\u01B0\u1EDDng truy\u1EC1n **RS-485 / Modbus RTU** l\xe0 c\xf4ng vi\u1EC7c th\u01B0\u1EDDng xuy\xean di\u1EC5n ra h\xe0ng ng\xe0y...\\n\\n\u0110\u1EC3 gi\u1EA3i quy\u1EBFt tri\u1EC7t \u0111\u1EC3 c\xe1c v\u1EA5n \u0111\u1EC1 n\xe0y, m\xecnh \u0111\xe3 x\xe2y d\u1EF1ng b\u1ED9 c\xf4ng c\u1EE5 **[Data Conversion Tool](pathname:///shareme/tool/)**...\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. Gi\u1EDBi thi\u1EC7u t\u1ED5ng quan v\u1EC1 Tool Data Conversion\\n\\nB\u1ED9 c\xf4ng c\u1EE5 **Data Conversion Tool** l\xe0 m\u1ED9t \u1EE9ng d\u1EE5ng web single-page \u0111a n\u0103ng gi\xfap N\xed nhanh ch\xf3ng ph\xe2n t\xedch, chuy\u1EC3n \u0111\u1ED5i v\xe0 \u0111\xf3ng g\xf3i d\u1EEF li\u1EC7u m\xe0 kh\xf4ng c\u1EA7n vi\u1EBFt code hay c\xe0i \u0111\u1EB7t c\xe1c ph\u1EA7n m\u1EC1m m\xf4 ph\u1ECFng ph\u1EE9c t\u1EA1p.\\n\\nGiao di\u1EC7n bao g\u1ED3m 6 tab ch\u1EE9c n\u0103ng chuy\xean bi\u1EC7t:\\n1. **H\u1EC7 c\u01A1 s\u1ED1 (Number Base Converter):** Chuy\u1EC3n \u0111\u1ED5i qua l\u1EA1i gi\u1EEFa Th\u1EADp ph\xe2n, Th\u1EADp l\u1EE5c ph\xe2n, Nh\u1ECB ph\xe2n v\xe0 B\xe1t ph\xe2n, \u0111\u1ED3ng th\u1EDDi t\xe1ch Byte/Word v\xe0 xem Bit Map.\\n2. **CRC16 (Modbus RTU Calculator):** T\xednh to\xe1n m\xe3 ki\u1EC3m tra l\u1ED7i 16-bit theo chu\u1EA9n Modbus RTU.\\n3. **Dec/Hex/Swap (Data Converter):** Chuy\u1EC3n \u0111\u1ED5i Dec $\\\\leftrightarrow$ Hex c\xf3/kh\xf4ng d\u1EA5u (8/16/32-bit) v\xe0 ho\xe1n \u0111\u1ED5i v\u1ECB tr\xed Byte/Word.\\n4. **Float $\\\\leftrightarrow$ Reg (IEEE 754 Converter):** Chuy\u1EC3n \u0111\u1ED5i s\u1ED1 th\u1EF1c 32-bit th\xe0nh hai thanh ghi Modbus 16-bit v\xe0 ng\u01B0\u1EE3c l\u1EA1i.\\n5. **Modbus Frame (RTU Builder):** T\u1EF1 \u0111\u1ED9ng t\u1EA1o khung truy\u1EC1n Modbus RTU chu\u1EA9n theo m\xe3 h\xe0m \u0111\u1ECDc/ghi.\\n6. **ASCII $\\\\leftrightarrow$ HEX Converter:** D\u1ECBch chu\u1ED7i k\xfd t\u1EF1 ASCII sang HEX bytes v\xe0 ng\u01B0\u1EE3c l\u1EA1i k\xe8m b\u1EA3ng tra c\u1EE9u m\xe3 \u0111i\u1EC1u khi\u1EC3n.\\n\\n---\\n\\n## 2. C\xf4ng d\u1EE5ng, C\xf4ng th\u1EE9c to\xe1n h\u1ECDc v\xe0 C\xe1ch \xe1p d\u1EE5ng c\u1EE7a t\u1EEBng Tab\\n\\n### 2.1. Tab 1: H\u1EC7 c\u01A1 s\u1ED1 (Number Base Converter)\\n\\n#### C\xf4ng d\u1EE5ng\\nChuy\u1EC3n \u0111\u1ED5i t\u1EE9c th\u1EDDi m\u1ED9t gi\xe1 tr\u1ECB s\u1ED1 gi\u1EEFa c\xe1c h\u1EC7 c\u01A1 s\u1ED1 ph\u1ED5 bi\u1EBFn: Th\u1EADp ph\xe2n (Dec), Th\u1EADp l\u1EE5c ph\xe2n (Hex), Nh\u1ECB ph\xe2n (Bin) v\xe0 B\xe1t ph\xe2n (Oct). \u0110\u1ED3ng th\u1EDDi ph\xe2n t\xedch m\u1ED9t s\u1ED1 nguy\xean l\u1EDBn th\xe0nh c\xe1c ph\u1EA7n nh\u1ECF h\u01A1n: **Low Byte, High Byte, Low Word, High Word** v\xe0 bi\u1EC3u di\u1EC5n d\u01B0\u1EDBi d\u1EA1ng s\u01A1 \u0111\u1ED3 Bit Map 16-bit tr\u1EF1c quan.\\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc\\n\u0110\u1EC3 chuy\u1EC3n \u0111\u1ED5i m\u1ED9t s\u1ED1 \u1EDF h\u1EC7 c\u01A1 s\u1ED1 <MathRenderer displayMode={false} formula={String.raw`b`} /> c\xf3 c\xe1c ch\u1EEF s\u1ED1 <MathRenderer displayMode={false} formula={String.raw`d_n d_{n-1} \\\\dots d_0`} /> sang h\u1EC7 th\u1EADp ph\xe2n (Dec):\\n<MathRenderer formula={String.raw`N_{10} = \\\\sum_{i=0}^{n} d_i \\\\cdot b^i = d_n \\\\cdot b^n + d_{n-1} \\\\cdot b^{n-1} + \\\\dots + d_0 \\\\cdot b^0`} />\\n\\n*V\xed d\u1EE5:* V\u1EDBi s\u1ED1 HEX <MathRenderer displayMode={false} formula={String.raw`FF_{16}`} />:\\n<MathRenderer formula={String.raw`N_{10} = F \\\\cdot 16^1 + F \\\\cdot 16^0 = 15 \\\\cdot 16 + 15 \\\\cdot 1 = 255_{10}`} />\\n\\nC\xf4ng th\u1EE9c t\xe1ch c\xe1c th\xe0nh ph\u1EA7n Byte v\xe0 Word t\u1EEB m\u1ED9t s\u1ED1 nguy\xean kh\xf4ng d\u1EA5u <MathRenderer displayMode={false} formula={String.raw`N`} />:\\n*   **Low Byte (Byte 0):** \\n    <MathRenderer formula={String.raw`N_{\\\\text{Low Byte}} = N \\\\pmod{2^8} = N \\\\ \\\\& \\\\ \\\\text{0xFF}`} />\\n*   **High Byte (Byte 1):** \\n    <MathRenderer formula={String.raw`N_{\\\\text{High Byte}} = \\\\lfloor \\\\frac{N}{2^8} \\\\rfloor \\\\pmod{2^8} = (N \\\\gg 8) \\\\ \\\\& \\\\ \\\\text{0xFF}`} />\\n*   **Low Word (Word 0):** \\n    <MathRenderer formula={String.raw`N_{\\\\text{Low Word}} = N \\\\pmod{2^{16}} = N \\\\ \\\\& \\\\ \\\\text{0xFFFF}`} />\\n*   **High Word (Word 1):** \\n    <MathRenderer formula={String.raw`N_{\\\\text{High Word}} = \\\\lfloor \\\\frac{N}{2^{16}} \\\\rfloor \\\\pmod{2^{16}} = (N \\\\gg 16) \\\\ \\\\& \\\\ \\\\text{0xFFFF}`} />\\n\\n*(Trong \u0111\xf3 <MathRenderer displayMode={false} formula={String.raw`\\\\&`} /> k\xfd hi\u1EC7u cho ph\xe9p to\xe1n bitwise AND, v\xe0 <MathRenderer displayMode={false} formula={String.raw`\\\\gg`} /> k\xfd hi\u1EC7u cho ph\xe9p to\xe1n d\u1ECBch ph\u1EA3i bitwise).*\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\nKhi c\u1EA5u h\xecnh b\u1EA3n \u0111\u1ED3 b\u1ED9 nh\u1EDB (Address Map) tr\xean HMI, ta th\u01B0\u1EDDng ph\u1EA3i ph\xe2n r\xe3 m\u1ED9t thanh ghi 16-bit th\xe0nh c\xe1c bit \u0111\u01A1n l\u1EBB (Bit Lamp/Bit Switch). V\xed d\u1EE5 thanh ghi tr\u1EA1ng th\xe1i m\xe1y c\xf3 gi\xe1 tr\u1ECB Dec l\xe0 `32768`, nh\u1EADp v\xe0o c\xf4ng c\u1EE5 s\u1EBD th\u1EA5y ngay bit th\u1EE9 `15` \u0111ang \u1EDF m\u1EE9c `1` (ON), c\xe1c bit kh\xe1c b\u1EB1ng `0` (OFF).\\n\\n---\\n\\n### 2.2. Tab 2: CRC16 Modbus Calculator\\n\\n#### C\xf4ng d\u1EE5ng\\nT\xednh to\xe1n m\xe3 ki\u1EC3m tra l\u1ED7i (Cyclic Redundancy Check) 16-bit cho m\u1ED9t chu\u1ED7i d\u1EEF li\u1EC7u \u0111\u1EA7u v\xe0o (h\u1EC7 HEX ho\u1EB7c chu\u1ED7i k\xfd t\u1EF1 ASCII). \u0110\u1EA7u ra tr\u1EA3 v\u1EC1 gi\xe1 tr\u1ECB CRC \u0111\u1EA7y \u0111\u1EE7, chia s\u1EB5n Byte th\u1EA5p (g\u1EEDi tr\u01B0\u1EDBc) v\xe0 Byte cao (g\u1EEDi sau) c\xf9ng khung truy\u1EC1n ho\xe0n ch\u1EC9nh k\xe8m m\xe3 ki\u1EC3m tra l\u1ED7i.\\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc (Thu\u1EADt to\xe1n CRC16 Modbus)\\nS\u1EED d\u1EE5ng \u0111a th\u1EE9c sinh (Polynomial): **<MathRenderer displayMode={false} formula={String.raw`0x8005`} />** \u0111\u1EA3o ng\u01B0\u1EE3c bit th\xe0nh **<MathRenderer displayMode={false} formula={String.raw`0xA001`} />**.\\nGi\xe1 tr\u1ECB kh\u1EDFi t\u1EA1o ban \u0111\u1EA7u (Initial Value) l\xe0 **<MathRenderer displayMode={false} formula={String.raw`0xFFFF`} />**.\\n\\nThu\u1EADt to\xe1n t\xednh to\xe1n t\u1EEBng byte nh\u01B0 sau:\\n1. G\xe1n gi\xe1 tr\u1ECB thanh ghi <MathRenderer displayMode={false} formula={String.raw`\\\\text{CRC} = \\\\text{0xFFFF}`} />.\\n2. V\u1EDBi m\u1ED7i byte d\u1EEF li\u1EC7u <MathRenderer displayMode={false} formula={String.raw`B_j`} /> trong chu\u1ED7i (<MathRenderer displayMode={false} formula={String.raw`j`} /> ch\u1EA1y t\u1EEB <MathRenderer displayMode={false} formula={String.raw`0`} /> \u0111\u1EBFn <MathRenderer displayMode={false} formula={String.raw`M-1`} />):\\n   <MathRenderer formula={String.raw`\\\\text{CRC} = \\\\text{CRC} \\\\oplus B_j`} />\\n3. Th\u1EF1c hi\u1EC7n l\u1EB7p 8 l\u1EA7n \u1EE9ng v\u1EDBi 8 bit (bi\u1EBFn ch\u1EA1y <MathRenderer displayMode={false} formula={String.raw`k`} /> t\u1EEB <MathRenderer displayMode={false} formula={String.raw`0`} /> \u0111\u1EBFn <MathRenderer displayMode={false} formula={String.raw`7`} />):\\n   <MathRenderer formula={String.raw`\\\\text{CRC}_{next} = \\\\begin{cases} (\\\\text{CRC} \\\\gg 1) \\\\oplus \\\\text{0xA001} & \\\\text{n\u1EBFu LSB}(\\\\text{CRC}) = 1 \\\\\\\\ \\\\text{CRC} \\\\gg 1 & \\\\text{n\u1EBFu LSB}(\\\\text{CRC}) = 0 \\\\end{cases}`} />\\n4. Sau khi duy\u1EC7t h\u1EBFt t\u1EA5t c\u1EA3 c\xe1c byte, gi\xe1 tr\u1ECB <MathRenderer displayMode={false} formula={String.raw`\\\\text{CRC}`} /> cu\u1ED1i c\xf9ng ch\xednh l\xe0 m\xe3 ki\u1EC3m tra l\u1ED7i. Theo chu\u1EA9n Modbus RTU, byte th\u1EA5p c\u1EE7a <MathRenderer displayMode={false} formula={String.raw`\\\\text{CRC}`} /> s\u1EBD \u0111\u01B0\u1EE3c ch\xe8n v\xe0o tr\u01B0\u1EDBc, byte cao ch\xe8n v\xe0o sau trong khung truy\u1EC1n.\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\nKhi n\xed vi\u1EBFt ch\u01B0\u01A1ng tr\xecnh vi \u0111i\u1EC1u khi\u1EC3n (Arduino/STM32) ho\u1EB7c Script trong Python/C# \u0111\u1EC3 giao ti\u1EBFp v\u1EDBi thi\u1EBFt b\u1ECB Modbus, n\xed c\xf3 th\u1EC3 nh\u1EADp th\u1EE7 c\xf4ng khung d\u1EEF li\u1EC7u v\xed d\u1EE5 `01 03 00 00 00 0A` v\xe0o c\xf4ng c\u1EE5 \u0111\u1EC3 l\u1EA5y nhanh CRC l\xe0 `0xC5CD` (Lo Byte: `C5`, Hi Byte: `CD`). D\xf9ng k\u1EBFt qu\u1EA3 n\xe0y \u0111\u1EC3 ki\u1EC3m tra xem thu\u1EADt to\xe1n m\xe3 h\xf3a trong ch\u01B0\u01A1ng tr\xecnh c\u1EE7a n\xed \u0111\xe3 vi\u1EBFt \u0111\xfang ch\u01B0a.\\n\\n---\\n\\n### 2.3. Tab 3: Dec/Hex/Swap (Data Converter)\\n\\n#### C\xf4ng d\u1EE5ng\\nH\u1ED7 tr\u1EE3 chuy\u1EC3n \u0111\u1ED5i n\xe2ng cao gi\u1EEFa s\u1ED1 Th\u1EADp ph\xe2n v\xe0 Th\u1EADp l\u1EE5c ph\xe2n c\xf3 t\xf9y ch\u1ECDn k\xedch th\u01B0\u1EDBc d\u1EEF li\u1EC7u (8-bit, 16-bit, 32-bit) v\xe0 ch\u1EBF \u0111\u1ED9 c\xf3 d\u1EA5u (Signed) ho\u1EB7c kh\xf4ng d\u1EA5u (Unsigned). \u0110\u1ED3ng th\u1EDDi hi\u1EC3n th\u1ECB k\u1EBFt qu\u1EA3 **Byte Swap** (cho d\u1EEF li\u1EC7u 16-bit) v\xe0 **Word Swap** (cho d\u1EEF li\u1EC7u 32-bit).\\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc\\n\u0110\u1ED1i v\u1EDBi s\u1ED1 nguy\xean c\xf3 d\u1EA5u (Signed) s\u1EED d\u1EE5ng bi\u1EC3u di\u1EC5n **B\xf9 2 (Two\'s Complement)**, m\u1ED9t s\u1ED1 nguy\xean kh\xf4ng d\u1EA5u <MathRenderer displayMode={false} formula={String.raw`X`} /> c\xf3 \u0111\u1ED9 r\u1ED9ng <MathRenderer displayMode={false} formula={String.raw`N`} />-bit s\u1EBD \u0111\u01B0\u1EE3c \xe1nh x\u1EA1 sang s\u1ED1 c\xf3 d\u1EA5u nh\u01B0 sau:\\n<MathRenderer formula={String.raw`X_{\\\\text{signed}} = \\\\begin{cases} X_{\\\\text{unsigned}} & \\\\text{n\u1EBFu } X_{\\\\text{unsigned}} < 2^{N-1} \\\\\\\\ X_{\\\\text{unsigned}} - 2^N & \\\\text{n\u1EBFu } X_{\\\\text{unsigned}} \\\\ge 2^{N-1} \\\\end{cases}`} />\\n\\n*V\xed d\u1EE5 16-bit (<MathRenderer displayMode={false} formula={String.raw`N=16`} />):*\\n*   N\u1EBFu \u0111\u1ECDc \u0111\u01B0\u1EE3c gi\xe1 tr\u1ECB HEX l\xe0 `FFFF` (Dec kh\xf4ng d\u1EA5u l\xe0 <MathRenderer displayMode={false} formula={String.raw`65535 \\\\ge 32768`} />):\\n    <MathRenderer formula={String.raw`X_{\\\\text{signed}} = 65535 - 65536 = -1`} />\\n*   **Ph\xe9p Byte Swap (16-bit):** \u0110\u1EA3o v\u1ECB tr\xed byte cao v\xe0 byte th\u1EA5p c\u1EE7a s\u1ED1 <MathRenderer displayMode={false} formula={String.raw`V_{16} = B_1 B_0`} />:\\n    <MathRenderer formula={String.raw`\\\\text{ByteSwap}(V_{16}) = (B_0 \\\\ll 8) \\\\ | \\\\ B_1`} />\\n*   **Ph\xe9p Word Swap (32-bit):** \u0110\u1EA3o v\u1ECB tr\xed 2 word 16-bit c\u1EE7a s\u1ED1 <MathRenderer displayMode={false} formula={String.raw`V_{32} = W_1 W_0`} />:\\n    <MathRenderer formula={String.raw`\\\\text{WordSwap}(V_{32}) = ((W_0 \\\\ \\\\& \\\\ \\\\text{0xFFFF}) \\\\ll 16) \\\\ | \\\\ (W_1 \\\\ \\\\& \\\\ \\\\text{0xFFFF})`} />\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\n*   **X\u1EED l\xfd s\u1ED1 \xe2m:** PLC \u0111\u1ECDc c\u1EA3m bi\u1EBFn nhi\u1EC7t \u0111\u1ED9 tr\u1EA3 v\u1EC1 gi\xe1 tr\u1ECB raw d\u1EA1ng s\u1ED1 nguy\xean 16-bit. C\u1EA3m bi\u1EBFn b\xe1o l\u1ED7i tr\u1EA3 v\u1EC1 `-1`. N\u1EBFu HMI \u0111\u1ECDc \u1EDF c\u1EA5u h\xecnh Unsigned s\u1EBD hi\u1EC3n th\u1ECB `65535` g\xe2y hi\u1EC3u nh\u1EA7m. C\xf4ng c\u1EE5 gi\xfap ta \u0111\u1ED1i chi\u1EBFu nhanh \u0111\u1EC3 nh\u1EADn d\u1EA1ng l\u1ED7i ki\u1EC3u d\u1EEF li\u1EC7u.\\n*   **Kh\u1EAFc ph\u1EE5c Byte/Word Swap:** Khi g\u1EEDi d\u1EEF li\u1EC7u t\u1EEB PLC h\xe3ng Siemens (Big-Endian) sang PLC h\xe3ng Mitsubishi (Little-Endian), th\u1EE9 t\u1EF1 byte ho\u1EB7c word th\u01B0\u1EDDng b\u1ECB \u0111\u1EA3o l\u1ED9n. Ch\u1EC9 c\u1EA7n nh\u1EADp gi\xe1 tr\u1ECB l\u1ED7i v\xe0o, xem k\u1EBFt qu\u1EA3 Swap \u0111\u1EC3 bi\u1EBFt c\u1EA5u h\xecnh ho\xe1n \u0111\u1ED5i n\xe0o l\xe0 ch\xednh x\xe1c.\\n\\n---\\n\\n### 2.4. Tab 4: Float $\\\\leftrightarrow$ Register (IEEE 754 Converter)\\n\\n#### C\xf4ng d\u1EE5ng\\nChuy\u1EC3n \u0111\u1ED5i m\u1ED9t s\u1ED1 th\u1EF1c 32-bit (Float 32) sang hai thanh ghi Modbus 16-bit (Holding Register) v\xe0 ng\u01B0\u1EE3c l\u1EA1i theo chu\u1EA9n **IEEE 754**. H\u1ED7 tr\u1EE3 l\u1EF1a ch\u1ECDn th\u1EE9 t\u1EF1 hi\u1EC3n th\u1ECB Word (High Word tr\u01B0\u1EDBc hay Low Word tr\u01B0\u1EDBc).\\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc (Chu\u1EA9n s\u1ED1 th\u1EF1c IEEE 754)\\nS\u1ED1 th\u1EF1c \u0111\u01A1n \u0111\u1ED9 ch\xednh x\xe1c (Single-precision floating-point) 32-bit g\u1ED3m 3 ph\u1EA7n:\\n1.  **Bit d\u1EA5u (Sign bit - <MathRenderer displayMode={false} formula={String.raw`s`} />):** 1 bit (bit 31).\\n2.  **Ph\u1EA7n m\u0169 (Exponent - <MathRenderer displayMode={false} formula={String.raw`E`} />):** 8 bit (bit 30 \u0111\u1EBFn 23).\\n3.  **Ph\u1EA7n \u0111\u1ECBnh tr\u1ECB (Fraction / Mantissa - <MathRenderer displayMode={false} formula={String.raw`M`} />):** 23 bit (bit 22 \u0111\u1EBFn 0).\\n\\nGi\xe1 tr\u1ECB th\u1EF1c <MathRenderer displayMode={false} formula={String.raw`V`} /> \u0111\u01B0\u1EE3c t\xednh b\u1EB1ng c\xf4ng th\u1EE9c:\\n<MathRenderer formula={String.raw`V = (-1)^s \\\\times \\\\left(1 + \\\\sum_{i=1}^{23} b_{23-i} \\\\cdot 2^{-i}\\\\right) \\\\times 2^{E - 127}`} />\\nHay vi\u1EBFt g\u1ECDn:\\n<MathRenderer formula={String.raw`V = (-1)^s \\\\times (1 + M) \\\\times 2^{E - 127}`} />\\n\\n*V\xed d\u1EE5:* S\u1ED1 th\u1EF1c <MathRenderer displayMode={false} formula={String.raw`3.14`} /> c\xf3 bi\u1EC3u di\u1EC5n nh\u1ECB ph\xe2n 32-bit l\xe0:\\n<MathRenderer formula={String.raw`\\\\text{0x4048F5C3} \\\\rightarrow \\\\text{High Word} = \\\\text{0x4048} \\\\ (16456), \\\\ \\\\text{Low Word} = \\\\text{0xF5C3} \\\\ (62915)`} />\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\nKhi PLC \u0111\u1ECDc th\xf4ng s\u1ED1 L\u01B0u l\u01B0\u1EE3ng (Flow rate) ho\u1EB7c \u0110i\u1EC7n n\u0103ng ti\xeau th\u1EE5 (kWh) d\u1EA1ng s\u1ED1 th\u1EF1c t\u1EEB \u0111\u1ED3ng h\u1ED3 \u0111o th\xf4ng qua giao th\u1EE9c Modbus, k\u1EBFt qu\u1EA3 tr\u1EA3 v\u1EC1 l\xe0 hai thanh ghi 16-bit \u0111\u1ED9c l\u1EADp. \\nN\u1EBFu n\xed nh\u1EADn \u0111\u01B0\u1EE3c hai gi\xe1 tr\u1ECB `16456` v\xe0 `62915` t\u1EEB \u0111\u1ED3ng h\u1ED3, ch\u1EC9 c\u1EA7n nh\u1EADp v\xe0o Tab 4 \u1EDF ch\u1EBF \u0111\u1ED9 Register $\\\\rightarrow$ Float s\u1EBD gi\u1EA3i m\xe3 \u0111\u01B0\u1EE3c ngay gi\xe1 tr\u1ECB th\u1EF1c l\xe0 `3.14`. N\u1EBFu ra s\u1ED1 k\u1EF3 l\u1EA1, h\xe3y chuy\u1EC3n \u0111\u1ED5i Word Order t\u1EEB **High Word tr\u01B0\u1EDBc (Big-Endian)** sang **Low Word tr\u01B0\u1EDBc (Little-Endian Word)** \u0111\u1EC3 d\xf2 xem thi\u1EBFt b\u1ECB c\u1EE7a n\xed \u0111ang g\u1EEDi theo chu\u1EA9n n\xe0o.\\n\\n---\\n\\n### 2.5. Tab 5: Modbus Frame (Modbus RTU Frame Builder)\\n\\n#### C\xf4ng d\u1EE5ng\\nGi\xfap t\u1EF1 \u0111\u1ED9ng \u0111\xf3ng g\xf3i m\u1ED9t khung truy\u1EC1n Modbus RTU ho\xe0n ch\u1EC9nh d\u1EF1a tr\xean c\xe1c tham s\u1ED1 c\u1EA5u h\xecnh: **Slave ID, Function Code (FC01 - FC10), Start Address, Quantity** v\xe0 **D\u1EEF li\u1EC7u ghi (Write Data)**. \\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc\\nKhung truy\u1EC1n Modbus RTU Application Data Unit (ADU) c\xf3 c\u1EA5u tr\xfac:\\n<MathRenderer formula={String.raw`\\\\text{ADU} = [\\\\text{Slave ID}] + [\\\\text{Function Code}] + [\\\\text{Data Field}] + [\\\\text{CRC16 Checksum}`} />\\n\\n*   **Slave ID (1 byte):** \u0110\u1ECBa ch\u1EC9 thi\u1EBFt b\u1ECB \u0111\xedch (<MathRenderer displayMode={false} formula={String.raw`0x01 - 0xF7`} />).\\n*   **Function Code (1 byte):** M\xe3 h\xe0m x\u1EED l\xfd d\u1EEF li\u1EC7u (<MathRenderer displayMode={false} formula={String.raw`0x01`} />: \u0111\u1ECDc Coil, <MathRenderer displayMode={false} formula={String.raw`0x03`} />: \u0111\u1ECDc thanh ghi, <MathRenderer displayMode={false} formula={String.raw`0x10`} />: ghi nhi\u1EC1u thanh ghi...).\\n*   **Data Field (<MathRenderer displayMode={false} formula={String.raw`N`} /> bytes):** \u0110\u1ECBa ch\u1EC9 b\u1EAFt \u0111\u1EA7u, s\u1ED1 l\u01B0\u1EE3ng, ho\u1EB7c gi\xe1 tr\u1ECB ghi c\u1EE5 th\u1EC3.\\n*   **CRC16 Checksum (2 bytes):** T\xednh theo thu\u1EADt to\xe1n CRC16 Modbus tr\xean to\xe0n b\u1ED9 c\xe1c byte tr\u01B0\u1EDBc \u0111\xf3.\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\nKhi ki\u1EC3m tra l\u1ED7i truy\u1EC1n th\xf4ng b\u1EB1ng c\xe1c c\xf4ng c\u1EE5 Terminal chuy\xean d\u1EE5ng nh\u01B0 Hercules, RealTerm, hay Docklight, n\xed kh\xf4ng th\u1EC3 g\u1EEDi tr\u1EF1c ti\u1EBFp l\u1EC7nh th\xf4 n\u1EBFu kh\xf4ng t\xednh m\xe3 CRC. Thay v\xec m\u1EDF c\xe1c ph\u1EA7n m\u1EC1m t\xednh CRC r\u1EDDi r\u1EA1c, n\xed ch\u1EC9 c\u1EA7n \u0111i\u1EC1n c\xe1c tham s\u1ED1 tr\u1EF1c quan trong Tab 5, copy to\xe0n b\u1ED9 khung Hex thu \u0111\u01B0\u1EE3c v\xe0 d\xe1n v\xe0o ph\u1EA7n m\u1EC1m Terminal \u0111\u1EC3 g\u1EEDi tr\u1EF1c ti\u1EBFp xu\u1ED1ng bi\u1EBFn t\u1EA7n, c\u1EA3m bi\u1EBFn.\\n\\n---\\n\\n### 2.6. Tab 6: ASCII $\\\\leftrightarrow$ HEX Converter\\n\\n#### C\xf4ng d\u1EE5ng\\nChuy\u1EC3n \u0111\u1ED5i nhanh ch\xf3ng gi\u1EEFa m\u1ED9t chu\u1ED7i k\xfd t\u1EF1 v\u0103n b\u1EA3n (ASCII) v\xe0 m\u1ED9t chu\u1ED7i m\xe3 HEX t\u01B0\u01A1ng \u1EE9ng (c\xe1ch nhau b\u1EDFi kho\u1EA3ng tr\u1EAFng). Tab n\xe0y c\u0169ng t\xedch h\u1EE3p s\u1EB5n b\u1EA3ng tra c\u1EE9u nhanh c\xe1c k\xfd t\u1EF1 \u0111i\u1EC1u khi\u1EC3n \u0111\u1EB7c bi\u1EC7t th\u01B0\u1EDDng g\u1EB7p trong giao th\u1EE9c truy\u1EC1n th\xf4ng c\xf4ng nghi\u1EC7p.\\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc\\nPh\xe9p chuy\u1EC3n \u0111\u1ED5i d\u1EF1a tr\xean b\u1EA3ng m\xe3 h\xf3a ti\xeau chu\u1EA9n ASCII, \xe1nh x\u1EA1 k\xfd t\u1EF1 <MathRenderer displayMode={false} formula={String.raw`c`} /> sang m\xe3 s\u1ED1 th\u1EADp l\u1EE5c ph\xe2n t\u01B0\u01A1ng \u1EE9ng:\\n<MathRenderer formula={String.raw`\\\\text{ASCII}(c) \\\\longleftrightarrow \\\\text{HEX Code}`} />\\n\\n*V\xed d\u1EE5:* K\xfd t\u1EF1 `\'A\'` c\xf3 m\xe3 Hex l\xe0 `41` (Dec: 65), k\xfd t\u1EF1 \u0111i\u1EC1u khi\u1EC3n b\u1EAFt \u0111\u1EA7u khung truy\u1EC1n `STX` (Start of Text) c\xf3 m\xe3 Hex l\xe0 `02`.\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\nNhi\u1EC1u thi\u1EBFt b\u1ECB c\xf4ng nghi\u1EC7p c\u0169 ho\u1EB7c \u0111\u1EA7u \u0111\u1ECDc m\xe3 v\u1EA1ch (Barcode Scanner), c\xe2n \u0111i\u1EC7n t\u1EED truy\u1EC1n th\xf4ng b\u1EB1ng giao th\u1EE9c ASCII th\xf4 qua c\u1ED5ng RS-232. Khung truy\u1EC1n th\u01B0\u1EDDng \u0111\u01B0\u1EE3c \u0111\u1ECBnh d\u1EA1ng ki\u1EC3u: `[STX] + D\u1EEF li\u1EC7u + [ETX]`. C\xf4ng c\u1EE5 n\xe0y gi\xfap n\xed d\u1ECBch c\xe1c chu\u1ED7i Hex \u0111\u1ECDc \u0111\u01B0\u1EE3c t\u1EEB c\u1ED5ng COM th\xe0nh chu\u1ED7i v\u0103n b\u1EA3n \u0111\u1ECDc \u0111\u01B0\u1EE3c v\xe0 ng\u01B0\u1EE3c l\u1EA1i.\\n\\n---\\n\\n## 3. T\u1ED5ng h\u1EE3p c\xe1ch kh\u1EAFc ph\u1EE5c c\xe1c l\u1ED7i th\u1EF1c t\u1EBF b\u1EB1ng Tool\\n\\n| T\xean l\u1ED7i truy\u1EC1n th\xf4ng | Bi\u1EC3u hi\u1EC7n th\u1EF1c t\u1EBF | C\xe1ch \xe1p d\u1EE5ng Tool \u0111\u1EC3 x\u1EED l\xfd |\\n| :--- | :--- | :--- |\\n| **L\u1ED7i 1: Sai th\u1EE9 t\u1EF1 Word (Word Swap / Endianness)** | \u0110\u1ECDc s\u1ED1 th\u1EF1c Float 32-bit t\u1EEB \u0111\u1ED3ng h\u1ED3 \u0111o, thay v\xec hi\u1EC3n th\u1ECB `220.5` V th\xec m\xe0n h\xecnh PLC hi\u1EC3n th\u1ECB m\u1ED9t s\u1ED1 c\u1EF1c l\u1EDBn ho\u1EB7c c\u1EF1c nh\u1ECF v\xf4 ngh\u0129a. | Nh\u1EADp hai thanh ghi HEX \u0111\u1ECDc \u0111\u01B0\u1EE3c v\xe0o **Tab 4 (Float $\\\\leftrightarrow$ Reg)**, th\u1EED \u0111\u1ED5i t\xf9y ch\u1ECDn th\u1EE9 t\u1EF1 Word gi\u1EEFa **High Word tr\u01B0\u1EDBc** v\xe0 **Low Word tr\u01B0\u1EDBc** cho \u0111\u1EBFn khi thu \u0111\u01B0\u1EE3c s\u1ED1 th\u1EF1c mong mu\u1ED1n. |\\n| **L\u1ED7i 2: Hi\u1EC3n th\u1ECB tr\xe0n s\u1ED1 \xe2m (Signed Mismatch)** | C\u1EA3m bi\u1EBFn l\u1EF1c k\xe9o hi\u1EC3n th\u1ECB t\u1EA3i tr\u1ECDng \xe2m `-50` kg nh\u01B0ng PLC l\u1EA1i hi\u1EC3n th\u1ECB `65486`. | Nh\u1EADp gi\xe1 tr\u1ECB `65486` v\xe0o ph\u1EA7n HEX c\u1EE7a **Tab 3 (Dec/Hex/Swap)**, ch\u1ECDn k\xedch th\u01B0\u1EDBc **16-bit** v\xe0 chuy\u1EC3n \u0111\u1ED5i qua l\u1EA1i gi\u1EEFa **Unsigned** v\xe0 **Signed** \u0111\u1EC3 \u0111\u1ED1i chi\u1EBFu c\xf4ng th\u1EE9c b\xf9 2. |\\n| **L\u1ED7i 3: Khung truy\u1EC1n b\u1ECB l\u1ED7i CRC (CRC Fail)** | G\u1EEDi l\u1EC7nh t\u1EEB PLC nh\u01B0ng bi\u1EBFn t\u1EA7n kh\xf4ng ph\u1EA3n h\u1ED3i, \u0111\xe8n RX/TX tr\xean c\u1ED5ng truy\u1EC1n th\xf4ng nh\xe1y \u0111\u1ECF c\u1EA3nh b\xe1o l\u1ED7i CRC. | Nh\u1EADp khung Hex c\u1EE7a l\u1EC7nh v\xe0o **Tab 2 (CRC16)** \u0111\u1EC3 t\xednh l\u1EA1i CRC, so s\xe1nh v\u1EDBi m\xe3 CRC \u0111ang g\u1EEDi trong PLC \u0111\u1EC3 xem c\xf3 b\u1ECB l\u1ED7i l\u1EADp tr\xecnh ho\u1EB7c \u0111\u1EA3o ng\u01B0\u1EE3c byte CRC hay kh\xf4ng. |\\n| **L\u1ED7i 4: G\u1EEDi sai \u0111\u1ECBa ch\u1EC9 thanh ghi Modbus** | G\u1EEDi l\u1EC7nh \u0111\u1ECDc thanh ghi nh\u01B0ng thi\u1EBFt b\u1ECB Slave tr\u1EA3 v\u1EC1 m\xe3 l\u1ED7i ngo\u1EA1i l\u1EC7 `02` (Illegal Data Address). | S\u1EED d\u1EE5ng **Tab 5 (Modbus Frame)** \u0111\u1EC3 x\xe2y d\u1EF1ng l\u1EA1i khung truy\u1EC1n chu\u1EA9n, l\u01B0u \xfd \u0111\u1ECBa ch\u1EC9 trong khung truy\u1EC1n Modbus th\u1EF1c t\u1EBF ph\u1EA3i tr\u1EEB \u0111i 1 \u0111\u01A1n v\u1ECB so v\u1EDBi \u0111\u1ECBa ch\u1EC9 tr\xean t\xe0i li\u1EC7u (v\xed d\u1EE5 \u0111\u1ECDc thanh ghi `40001` th\xec \u0111i\u1EC1n Start Address l\xe0 `0000`). |\\n\\n---\\n\\n## 4. \u0110\xe1nh gi\xe1 \u01B0u \u0111i\u1EC3m & Nh\u01B0\u1EE3c \u0111i\u1EC3m c\u1EE7a Tool\\n\\n### \u01AFu \u0111i\u1EC3m\\n*   **T\u1EA5t c\u1EA3 trong m\u1ED9t (All-in-One):** T\xedch h\u1EE3p t\u1EA5t c\u1EA3 c\xe1c ti\u1EC7n \xedch chuy\u1EC3n \u0111\u1ED5i c\u1EA7n thi\u1EBFt nh\u1EA5t cho d\xe2n l\u1EADp tr\xecnh \u0111i\u1EC1u khi\u1EC3n t\u1EF1 \u0111\u1ED9ng h\xf3a tr\xean m\u1ED9t trang duy nh\u1EA5t.\\n*   **Ph\u1EA3n h\u1ED3i th\u1EDDi gian th\u1EF1c (Real-time):** Nh\u1EADp gi\xe1 tr\u1ECB \u1EDF b\u1EA5t c\u1EE9 \xf4 n\xe0o, to\xe0n b\u1ED9 c\xe1c \xf4 c\xf2n l\u1EA1i t\u1EF1 \u0111\u1ED9ng t\xednh to\xe1n v\xe0 c\u1EADp nh\u1EADt ngay l\u1EADp t\u1EE9c.\\n*   **Ph\xe2n t\xedch khung tr\u1EF1c quan:** Gi\xfap b\xf3c t\xe1ch c\xe1c th\xe0nh ph\u1EA7n trong g\xf3i tin Modbus (ID, FC, Addr, CRC) m\u1ED9t c\xe1ch sinh \u0111\u1ED9ng, r\u1EA5t h\u1EEFu \xedch cho \u0111\xe0o t\u1EA1o v\xe0 nghi\xean c\u1EE9u.\\n*   **Giao di\u1EC7n hi\u1EC7n \u0111\u1EA1i:** T\u1ED1i \u01B0u hi\u1EC3n th\u1ECB tr\xean c\u1EA3 \u0111i\u1EC7n tho\u1EA1i v\xe0 m\xe1y t\xednh, h\u1ED7 tr\u1EE3 copy nhanh k\u1EBFt qu\u1EA3 qua m\u1ED9t n\xfat nh\u1EA5n b\u1EA5m ti\u1EC7n d\u1EE5ng.\\n\\n### Nh\u01B0\u1EE3c \u0111i\u1EC3m\\n*   **Ch\u01B0a h\u1ED7 tr\u1EE3 c\xe1c thu\u1EADt to\xe1n CRC kh\xe1c:** Hi\u1EC7n t\u1EA1i c\xf4ng c\u1EE5 m\u1EDBi ch\u1EC9 h\u1ED7 tr\u1EE3 t\xednh to\xe1n CRC16 Modbus (\u0111a th\u1EE9c $0xA001$). Ch\u01B0a t\xedch h\u1EE3p c\xe1c chu\u1EA9n CRC ph\u1ED5 bi\u1EBFn kh\xe1c nh\u01B0 CRC8, CRC32, hay CRC16-CCITT.\\n*   **Ch\u01B0a h\u1ED7 tr\u1EE3 k\u1EBFt n\u1ED1i ph\u1EA7n c\u1EE9ng:** Ch\u01B0a h\u1ED7 tr\u1EE3 t\xednh n\u0103ng Web Serial API \u0111\u1EC3 g\u1EEDi tr\u1EF1c ti\u1EBFp d\u1EEF li\u1EC7u t\u1EEB tr\xecnh duy\u1EC7t xu\u1ED1ng c\u1ED5ng COM v\u1EADt l\xfd c\u1EE7a m\xe1y t\xednh (ch\u1EC9 d\u1EEBng l\u1EA1i \u1EDF ph\xe2n t\xedch t\u0129nh).\\n\\n---\\n\\n## 5. K\u1EBFt lu\u1EADn\\n\\nB\u1ED9 c\xf4ng c\u1EE5 **Data Conversion Tool** l\xe0 tr\u1EE3 th\u1EE7 \u0111\u1EAFc l\u1EF1c gi\xfap r\xfat ng\u1EAFn th\u1EDDi gian chu\u1EA9n \u0111o\xe1n v\xe0 kh\u1EAFc ph\u1EE5c l\u1ED7i truy\u1EC1n th\xf4ng c\xf4ng nghi\u1EC7p. Vi\u1EC7c hi\u1EC3u r\xf5 c\xe1c c\xf4ng th\u1EE9c to\xe1n h\u1ECDc \u0111\u1EE9ng sau nh\u01B0 IEEE 754, Two\'s Complement b\xf9 2 hay c\u01A1 ch\u1EBF CRC16 gi\xfap ch\xfang ta l\xe0m ch\u1EE7 ho\xe0n to\xe0n d\u1EEF li\u1EC7u c\u1EE7a h\u1EC7 th\u1ED1ng \u0111i\u1EC1u khi\u1EC3n. H\xe3y truy c\u1EADp trang **[Tool Chuy\u1EC3n \u0110\u1ED5i D\u1EEF Li\u1EC7u](pathname:///shareme/tool/)** \u0111\u1EC3 tr\u1EA3i nghi\u1EC7m v\xe0 t\u1ED1i \u01B0u h\xf3a c\xf4ng vi\u1EC7c c\u1EE7a n\xed ngay h\xf4m nay!"}]}}')}}]);